/// Save a canvas snapshot to disk
#[tauri::command]
pub async fn save_canvas_snapshot(
    app: AppHandle,
    snapshot: CanvasSnapshot,
) -> Result<String, String> {
    let app_data = app
        .path()
        .app_data_dir()
        .map_err(|e| format!("Failed to get app data dir: {}", e))?;

    let snapshots_dir = app_data.join("snapshots").join(&snapshot.canvas_id);
    fs::create_dir_all(&snapshots_dir)
        .map_err(|e| format!("Failed to create snapshots dir: {}", e))?;

    let file_path = snapshots_dir.join(format!("{}.json", snapshot.id));
    let json = serde_json::to_string_pretty(&snapshot)
        .map_err(|e| format!("Failed to serialize snapshot: {}", e))?;

    fs::write(&file_path, json)
        .map_err(|e| format!("Failed to write snapshot: {}", e))?;

    log::info!("Saved snapshot: {:?}", file_path);
    Ok(file_path.to_string_lossy().to_string())
}

