/// Export canvas as image or JSON
#[tauri::command]
pub async fn export_canvas(
    app: AppHandle,
    canvas_id: String,
    format: String,
    content: String,
) -> Result<ExportResult, String> {
    let downloads = app
        .path()
        .download_dir()
        .map_err(|e| format!("Failed to get downloads dir: {}", e))?;

    let filename = match format.as_str() {
        "png" | "jpg" | "jpeg" => format!("{}.{}", canvas_id, format),
        "json" => format!("{}.json", canvas_id),
        "svg" => format!("{}.svg", canvas_id),
        _ => return Err(format!("Unsupported format: {}", format)),
    };

    let file_path = downloads.join(&filename);

    if format == "json" || format == "svg" {
        fs::write(&file_path, &content)
            .map_err(|e| format!("Failed to write export: {}", e))?;
    } else {
        // Binary: content is base64 encoded
        use base64::Engine;
        use std::io::Write;
        let decoded = base64::engine::general_purpose::STANDARD
            .decode(&content)
            .map_err(|_| "Failed to decode base64 content")?;
        let mut file = fs::File::create(&file_path)
            .map_err(|e| format!("Failed to create file: {}", e))?;
        file.write_all(&decoded)
            .map_err(|e| format!("Failed to write binary: {}", e))?;
    }

    log::info!("Exported canvas to: {:?}", file_path);
    Ok(ExportResult {
        path: file_path.to_string_lossy().to_string(),
        format,
    })
}

